SELECT b.id, b.menu_id, b.code, b.name, b.description, b.created_at, creator.username AS creator, b.updated_at, COALESCE(updater.username, 'Unknown') AS updater FROM sys_button b LEFT JOIN sys_user creator ON b.created_by = creator.id LEFT JOIN sys_user updater ON b.updated_by = updater.id
AND b.menu_id = #{menuId}
${ew.customSqlSegment}

